//! wasm32 export surface — the gnosis json-v1 ABI, verbatim
//! (`gnosis/src/wasm-execution-bridge.ts` names):
//!
//! - `memory`                       — rustc exports linear memory by default
//! - `gnosis_alloc(len) -> ptr`     — host allocates the input buffer
//! - `main(ptr, len) -> out_ptr`    — run; result bytes are VALID JSON
//! - `gnosis_result_len() -> len`
//! - `gnosis_free(ptr, len)`
//!
//! Decline = trap: any `WalkError` (or internal panic) aborts —
//! `panic = "abort"` in the release profile lowers to `unreachable` — and the
//! host falls back to the interpreter. Zero imports: the module is pure
//! computation over its input bytes (no clock, no fs, no host glue).
//!
//! C-ABI style mirrors `open-source/swerve/src/wasm.rs`.

use std::alloc::{alloc, Layout};
use std::cell::UnsafeCell;

/// Result bytes of the last `main` call, owned by the module. wasm32-unknown-
/// unknown is single-threaded; the UnsafeCell wrapper only exists to give the
/// static a `Sync` bound.
struct ResultCell(UnsafeCell<Vec<u8>>);
// SAFETY: wasm32-unknown-unknown has no threads; there is exactly one caller.
unsafe impl Sync for ResultCell {}

static RESULT: ResultCell = ResultCell(UnsafeCell::new(Vec::new()));

/// json-v1: allocate `len` bytes for the host to write the input envelope.
///
/// # Safety
/// Returned pointer is valid for exactly `len` bytes until `gnosis_free`.
#[no_mangle]
pub extern "C" fn gnosis_alloc(len: i32) -> i32 {
    if len <= 0 {
        panic!("gnosis_alloc: non-positive length");
    }
    // SAFETY: size > 0, align 1 is always valid.
    let ptr = unsafe { alloc(Layout::from_size_align(len as usize, 1).unwrap()) };
    if ptr.is_null() {
        panic!("gnosis_alloc: out of memory");
    }
    ptr as i32
}

/// json-v1 entry point. Input bytes are the envelope: v1
/// `{"topology": …, "input": …}`, v2 `+ "helpers"`, or v3 `+ optional
/// "budget"/cursor` for bounded/resumable walks (see crate docs). Returns a
/// pointer to the UTF-8 JSON result; length via `gnosis_result_len`.
///
/// # Safety
/// `ptr` must point to `len` readable bytes (host writes into a
/// `gnosis_alloc` buffer).
#[export_name = "main"]
pub unsafe extern "C" fn gnosis_main(ptr: i32, len: i32) -> i32 {
    if ptr <= 0 || len <= 0 {
        panic!("main: invalid input pointer/length");
    }
    let bytes = std::slice::from_raw_parts(ptr as u32 as *const u8, len as usize);
    let out = match crate::run_envelope_bytes(bytes) {
        Ok(json) => json.into_bytes(),
        // Fail closed: decline = trap (abort → unreachable).
        Err(e) => panic!("{e}"),
    };
    let cell = &mut *RESULT.0.get();
    *cell = out;
    cell.as_ptr() as i32
}

#[no_mangle]
pub extern "C" fn gnosis_result_len() -> i32 {
    // SAFETY: single-threaded; see ResultCell.
    unsafe { (*RESULT.0.get()).len() as i32 }
}

/// Free a `gnosis_alloc` buffer.
///
/// # Safety
/// `(ptr, len)` must be exactly a live `gnosis_alloc(len)` allocation.
#[no_mangle]
pub unsafe extern "C" fn gnosis_free(ptr: i32, len: i32) {
    // Deliberate no-op. The json-v1 hosts (wasm-execution-bridge.ts,
    // swerve exec/wasm.rs) free BOTH the input pointer they alloc'd AND
    // the output pointer `main` returned — but the output points into
    // the module-owned RESULT buffer, not an `alloc` block, so a real
    // `dealloc` here is UB (trap). Hosts instantiate fresh per
    // execution, so leaking the one input allocation is bounded by the
    // instance's lifetime — the same "no-op free" contract the Tier A
    // emitted modules declare.
    let _ = (ptr, len);
}
